#include <stdio.h>
#include <stdlib.h>

int *head, *to, *nextEdge;
int edgeCnt;
int *color;
int N, M;

void addEdge(int u, int v) {
    to[edgeCnt] = v;
    nextEdge[edgeCnt] = head[u];
    head[u] = edgeCnt++;
}

int dfs(int u) {
    color[u] = 1; // gray
    for (int e = head[u]; e != -1; e = nextEdge[e]) {
        int v = to[e];
        if (color[v] == 0) {
            if (dfs(v)) return 1;
        } else if (color[v] == 1) {
            return 1; // back edge found
        }
    }
    color[u] = 2; // black
    return 0;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d", &N, &M);
        head = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) head[i] = -1;
        to = (int*)malloc(M * sizeof(int));
        nextEdge = (int*)malloc(M * sizeof(int));
        edgeCnt = 0;
        for (int i = 0; i < M; ++i) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--; v--;
            addEdge(u, v);
        }
        color = (int*)calloc(N, sizeof(int));
        int hasCycle = 0;
        for (int i = 0; i < N && !hasCycle; ++i) {
            if (color[i] == 0) {
                if (dfs(i)) hasCycle = 1;
            }
        }
        printf("%s\n", hasCycle ? "YES" : "NO");
        free(head);
        free(to);
        free(nextEdge);
        free(color);
    }
    return 0;
}

