import sys
sys.setrecursionlimit(1_000_000)

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); m = int(next(it))
        adj = [[] for _ in range(n)]
        for _ in range(m):
            u = int(next(it)) - 1
            v = int(next(it)) - 1
            adj[u].append(v)
        color = [0] * n
        def dfs(u):
            color[u] = 1
            for v in adj[u]:
                if color[v] == 0:
                    if dfs(v):
                        return True
                elif color[v] == 1:
                    return True
            color[u] = 2
            return False
        has_cycle = False
        for i in range(n):
            if color[i] == 0:
                if dfs(i):
                    has_cycle = True
                    break
        out_lines.append('YES' if has_cycle else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

